        especie_faturamento: especieFaturamento,
        data_faturamento: dataFaturamento,
        numero_documento_origem: doc.numeroDocumento?.replace(/^0+/, '') || null,
        especie_documento_origem: doc.especieDocumento || null,
        data_entrada_origem: doc.dataEntrada || null,
        codigo_vendedor: doc.codigoVendedor || null,
        nome_vendedor: doc.nomeVendedor || null,
        codigo_cliente: doc.cliente?.codigoCliente?.replace(/^0+/, '') || null,
        nome_cliente: doc.cliente?.nome || doc.nomeConsumidorOuCliente || null,
        telefone1: doc.cliente?.telefone1?.replace(/\D/g, '') || null,
        telefone2: doc.cliente?.telefone2?.replace(/\D/g, '') || null,
        telefone_celular: doc.cliente?.telefoneCelular?.replace(/\D/g, '') || null,
        valor_contabil: valorContabil,
        valor_total_itens: 0,
        valor_frete: 0,
        quantidade_itens: 0,
        total_st: doc.totalST || 0,
        total_ipi: doc.totalIPI || 0,
        desconto_especial: doc.descontoEspecial || 0,
        total_desconto_itens: 0
      });
    }

    const fat = faturamentos.get(key);
    fat.valor_total_itens += item.totalItem || 0;
    fat.valor_frete += item.totalFrete || 0;
    fat.quantidade_itens += 1;

    const precoOrig = item.precoOriginal || 0;
    const precoUnit = item.precoUnitario || 0;
    const qtd = item.quantidade || 1;
    const descItem = precoOrig - precoUnit;
    if (descItem > 0 && descItem < precoUnit * 2) {
      fat.total_desconto_itens += descItem * qtd;
    }
  }
}

// ============ PROCESSA ITENS ============
const itensArray = [];

for (const doc of content) {
  if (!doc.jaFaturado) continue;
  const docItens = doc.itens || [];

  for (const item of docItens) {
    const numeroFaturamento = item.numeroFaturamento?.replace(/^0+/, '');
    const especieFaturamento = item.especieFaturamento;
    const dataFaturamento = item.dataFaturamento;

    if (!numeroFaturamento || !especieFaturamento) continue;
    if (!ESPECIES_FISCAIS.includes(especieFaturamento)) continue;
    if (!dataFaturamento) continue;

    const precoDigitado = item.precoDigitado || item.precoUnitario || 0;
    const totalCusto = item.totalCusto || 0;
    const quantidade = item.quantidade || 1;
    const custoUnitario = quantidade > 0 ? totalCusto / quantidade : 0;
    const margem = precoDigitado > 0
      ? Number(((precoDigitado - custoUnitario) / precoDigitado * 100).toFixed(2))
      : 0;

    const descricaoCompleta = item.descricaoCompleta || item.descricaoProduto || '';
    let medidaMatch = descricaoCompleta.match(/(\d+(?:[.,]\d+)?)\s*(L|KG|ML|G)\b/i);
    if (!medidaMatch) {
      medidaMatch = descricaoCompleta.match(/(\d+(?:[.,]\d+)?)\s*BD\b/i);
    }

    let unidade_medida = null;
    if (medidaMatch) {
      let valor = parseFloat(medidaMatch[1].replace(',', '.'));
      const unidade = (medidaMatch[2] || 'L').toUpperCase();
      if (unidade === 'ML') { valor = valor / 1000; unidade_medida = valor + 'L'; }
      else if (unidade === 'G' && valor >= 100) { valor = valor / 1000; unidade_medida = valor + 'KG'; }
      else if (unidade === 'BD' || unidade === 'L') { unidade_medida = valor + 'L'; }
      else { unidade_medida = valor + unidade; }
    }

    const precoOriginal = item.precoOriginal || 0;
    const precoUnitario = item.precoUnitario || 0;
    const descontoValor = precoOriginal > precoUnitario ? Number((precoOriginal - precoUnitario).toFixed(2)) : 0;
    const descontoPercentual = precoOriginal > 0 && descontoValor > 0 ? Number((descontoValor / precoOriginal * 100).toFixed(2)) : 0;

    itensArray.push({
      empresa_id: EMPRESA_ID,
      loja_id: LOJA_ID,
      codigo_loja: CODIGO_LOJA,
      numero_faturamento: numeroFaturamento,
      especie_faturamento: especieFaturamento,
      data_faturamento: dataFaturamento,
      codigo_vendedor: doc.codigoVendedor || null,
      nome_vendedor: doc.nomeVendedor || null,
      codigo_cliente: doc.cliente?.codigoCliente?.replace(/^0+/, '') || null,
      nome_cliente: doc.cliente?.nome || doc.nomeConsumidorOuCliente || null,
      codigo_produto: item.codigoProduto || '',
      descricao_produto: item.descricaoProduto || '',
      codigo_marca: item.codigoMarca || '',
      unidade_medida: unidade_medida,
      quantidade: quantidade,
      preco_unitario: precoUnitario,
      preco_original: precoOriginal,
      desconto_valor: descontoValor,
      desconto_percentual: descontoPercentual,
      margem_percentual: margem,
      total_item: item.totalItem || 0,
      total_frete: item.totalFrete || 0,
      total_st: item.totalST || 0
    });
  }
}

// Sequencial para itens com mesmo codigo_produto
const seqMap = new Map();
for (const it of itensArray) {
  const key = it.codigo_loja + '-' + it.especie_faturamento + '-' + it.numero_faturamento + '-' + it.codigo_produto;
  const seq = (seqMap.get(key) || 0) + 1;
  seqMap.set(key, seq);
  it.item_seq = seq;
}

// ============ MONTA SQL ============
const queries = [];

// SQL Faturamentos
const fats = Array.from(faturamentos.values());
if (fats.length > 0) {
  const values = fats.map(f => {
    return '(' + [
      esc(f.empresa_id), esc(f.loja_id), esc(f.codigo_loja), esc(f.codigo_empresa_expedicao),
      esc(f.numero_faturamento), esc(f.especie_faturamento), esc(f.data_faturamento),
      esc(f.numero_documento_origem), esc(f.especie_documento_origem), esc(f.data_entrada_origem),
      esc(f.codigo_vendedor), esc(f.nome_vendedor), esc(f.codigo_cliente), esc(f.nome_cliente),
      esc(f.telefone1), esc(f.telefone2), esc(f.telefone_celular),
      num(f.valor_contabil).toFixed(2), num(f.valor_total_itens).toFixed(2), num(f.valor_frete).toFixed(2),
      num(f.quantidade_itens), num(f.total_st), num(f.total_ipi),
      num(f.desconto_especial), num(f.total_desconto_itens + f.desconto_especial).toFixed(2)
    ].join(', ') + ')';
  }).join(',\n');

  queries.push(`INSERT INTO "Controle_TMC".faturamentos_fiscais (
  empresa_id, loja_id, codigo_loja, codigo_empresa_expedicao,
  numero_faturamento, especie_faturamento, data_faturamento,
  numero_documento_origem, especie_documento_origem, data_entrada_origem,
  codigo_vendedor, nome_vendedor, codigo_cliente, nome_cliente,
  telefone1, telefone2, telefone_celular,
  valor_contabil, valor_total_itens, valor_frete,
  quantidade_itens, total_st, total_ipi,
  desconto_especial, total_desconto_itens
) VALUES
${values}
ON CONFLICT (codigo_loja, especie_faturamento, numero_faturamento, codigo_empresa_expedicao)
DO UPDATE SET
  valor_contabil = EXCLUDED.valor_contabil,
  valor_total_itens = EXCLUDED.valor_total_itens,
  valor_frete = EXCLUDED.valor_frete,
  quantidade_itens = EXCLUDED.quantidade_itens,
  codigo_vendedor = EXCLUDED.codigo_vendedor,
  nome_vendedor = EXCLUDED.nome_vendedor,
  codigo_cliente = EXCLUDED.codigo_cliente,
  nome_cliente = EXCLUDED.nome_cliente,
  telefone1 = EXCLUDED.telefone1,
  telefone2 = EXCLUDED.telefone2,
  telefone_celular = EXCLUDED.telefone_celular,
  total_st = EXCLUDED.total_st,
  total_ipi = EXCLUDED.total_ipi,
  desconto_especial = EXCLUDED.desconto_especial,
  total_desconto_itens = EXCLUDED.total_desconto_itens,
  updated_at = NOW();`);
}

// SQL Itens
if (itensArray.length > 0) {
  const values = itensArray.map(i => {
    return '(' + [
      esc(i.empresa_id), esc(i.loja_id), esc(i.codigo_loja),
      esc(i.numero_faturamento), esc(i.especie_faturamento), esc(i.data_faturamento),
      esc(i.codigo_vendedor), esc(i.nome_vendedor), esc(i.codigo_cliente), esc(i.nome_cliente),
      esc(i.codigo_produto), esc(i.descricao_produto), esc(i.codigo_marca), esc(i.unidade_medida),
      num(i.quantidade), num(i.preco_unitario), num(i.preco_original),
      num(i.total_item), num(i.total_frete), num(i.margem_percentual),
      num(i.desconto_valor), num(i.desconto_percentual), num(i.item_seq), num(i.total_st)
    ].join(', ') + ')';
  }).join(',\n');

  queries.push(`INSERT INTO "Controle_TMC".itens_faturados (
  empresa_id, loja_id, codigo_loja,
  numero_faturamento, especie_faturamento, data_faturamento,
  codigo_vendedor, nome_vendedor, codigo_cliente, nome_cliente,
  codigo_produto, descricao_produto, codigo_marca, unidade_medida,
  quantidade, preco_unitario, preco_original,
  total_item, total_frete, margem_percentual,
  desconto_valor, desconto_percentual, item_seq, total_st
) VALUES
${values}
ON CONFLICT (codigo_loja, especie_faturamento, numero_faturamento, codigo_produto, item_seq)
DO UPDATE SET
  quantidade = EXCLUDED.quantidade,
  preco_unitario = EXCLUDED.preco_unitario,
  preco_original = EXCLUDED.preco_original,
  total_item = EXCLUDED.total_item,
  total_frete = EXCLUDED.total_frete,
  margem_percentual = EXCLUDED.margem_percentual,
  desconto_valor = EXCLUDED.desconto_valor,
  desconto_percentual = EXCLUDED.desconto_percentual,
  total_st = EXCLUDED.total_st,
  updated_at = NOW();`);
}

// Sempre rodar acompanhamento (mesmo sem faturamentos novos, pode ter de dias anteriores)
queries.push('SELECT * FROM "Controle_TMC".process_acompanhamento(' + esc(EMPRESA_ID) + '::uuid, ' + esc(CODIGO_LOJA) + ');');

// Contagem final
queries.push('SELECT ' + fats.length + ' as faturamentos, ' + itensArray.length + ' as itens;');

return [{ json: { query: queries.join('\n\n'), _stats: { faturamentos: fats.length, itens: itensArray.length } } }];
